const trigger = $('Execute Workflow Trigger').first().json;
const deal_id = trigger.deal_id || 'unknown';
const query = trigger.query || '';

const qdrantResponse = $input.first().json;
const hits = qdrantResponse.result || [];

if (hits.length === 0) {
  return [{ json: { result: `No documents found in the knowledge base for deal ${deal_id} matching: "${query}". The deal may not have been ingested yet.` } }];
}

const passages = hits
  .filter(h => (h.score || 0) > 0.25)
  .map(h => {
    const p = h.payload || {};
    const date = p.date_created ? new Date(p.date_created).toISOString().split('T')[0] : 'unknown';
    return `[${p.doc_type || 'document'}, ${date}, score: ${(h.score || 0).toFixed(3)}]\n${p.page_content || '(no content)'}`.trim();
  });

if (passages.length === 0) {
  return [{ json: { result: `Found ${hits.length} results for deal ${deal_id} but all scored below relevance threshold (0.25). Try a more specific query.` } }];
}

const result = `## RAG Results for ${deal_id} — "${query}"\n\nFound ${passages.length} relevant passage(s):\n\n${passages.join('\n\n---\n\n')}`;

return [{ json: { result } }];
